CREATE TABLE IF NOT EXISTS drivers (id BIGSERIAL PRIMARY KEY, name TEXT NOT NULL, mobile TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS deleted_drivers (id BIGINT PRIMARY KEY, name TEXT NOT NULL, mobile TEXT, created_at TIMESTAMPTZ, deleted_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), deleted_by TEXT NOT NULL DEFAULT 'user');
CREATE TABLE IF NOT EXISTS buses (id BIGSERIAL PRIMARY KEY, bus_number TEXT NOT NULL UNIQUE, assigned_driver_id BIGINT REFERENCES drivers(id) ON DELETE SET NULL, status TEXT NOT NULL DEFAULT 'Active', created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS deleted_buses (id BIGINT PRIMARY KEY, bus_number TEXT NOT NULL, assigned_driver_id BIGINT, status TEXT, created_at TIMESTAMPTZ, deleted_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), deleted_by TEXT NOT NULL DEFAULT 'user');
CREATE TABLE IF NOT EXISTS bills (id BIGSERIAL PRIMARY KEY, bill_no TEXT NOT NULL UNIQUE, date DATE NOT NULL, driver_name TEXT, bus_no TEXT, moklnar_name TEXT, moklnar_mobile TEXT, lenar_name TEXT, lenar_mobile TEXT, total NUMERIC(12,2) NOT NULL DEFAULT 0, jama NUMERIC(12,2) NOT NULL DEFAULT 0, baki NUMERIC(12,2) NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS deleted_bills (id BIGINT PRIMARY KEY, bill_no TEXT NOT NULL, date DATE NOT NULL, driver_name TEXT, bus_no TEXT, moklnar_name TEXT, moklnar_mobile TEXT, lenar_name TEXT, lenar_mobile TEXT, total NUMERIC(12,2) DEFAULT 0, jama NUMERIC(12,2) DEFAULT 0, baki NUMERIC(12,2) DEFAULT 0, created_at TIMESTAMPTZ, deleted_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), deleted_by TEXT NOT NULL DEFAULT 'user');
CREATE TABLE IF NOT EXISTS bill_items (id BIGSERIAL PRIMARY KEY, bill_id BIGINT NOT NULL REFERENCES bills(id) ON DELETE CASCADE, from_city TEXT DEFAULT 'Rajkot', to_city TEXT DEFAULT 'Surat', description TEXT, qty INTEGER NOT NULL DEFAULT 1, remark TEXT, amount NUMERIC(12,2) NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS deleted_bill_items (id BIGINT PRIMARY KEY, bill_id BIGINT NOT NULL, from_city TEXT, to_city TEXT, description TEXT, qty INTEGER, remark TEXT, amount NUMERIC(12,2), created_at TIMESTAMPTZ, deleted_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), deleted_by TEXT NOT NULL DEFAULT 'user');
CREATE TABLE IF NOT EXISTS users (id BIGSERIAL PRIMARY KEY, name TEXT NOT NULL, email TEXT UNIQUE NOT NULL, password TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS sessions (id BIGSERIAL PRIMARY KEY, user_id BIGINT NOT NULL REFERENCES users(id) ON DELETE CASCADE, token TEXT UNIQUE NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), expires_at TIMESTAMPTZ NOT NULL);
CREATE TABLE IF NOT EXISTS today_driver_assignments (id BIGSERIAL PRIMARY KEY, bus_id BIGINT NOT NULL REFERENCES buses(id) ON DELETE CASCADE, driver_id BIGINT NOT NULL REFERENCES drivers(id) ON DELETE CASCADE, assigned_date DATE NOT NULL DEFAULT CURRENT_DATE, assigned_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE(bus_id, assigned_date), UNIQUE(driver_id, assigned_date));
